using NP std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
		return;
	}
}
using NP phigrOS;
bool a[105][105];
int n,m,k,u,v,c[105],cnt;
bool ok(int x,int y)
{
	for(int i=1;i<=n;i++)
	{
		if(a[i][x]&&c[i]==y)
		{
			return 0;
		}
	}
	return 1;
}
void dfs(int x)
{
	if(x==n+1)
	{
		cnt++;
	}
	else
	{
		for(int i=1;i<=k;i++)
		{
			if(ok(x,i))
			{
				c[x]=i;
				dfs(x+1);
				c[x]=0;
			}
		}
	}
}
signed main(void)
{
	n=read();
	m=read();
	k=read();
	for(int i=1;i<=m;i++)
	{
		u=read();
		v=read();
		a[u][v]=1;
		a[v][u]=1;
	}
	dfs(1);
	writeln(cnt);
	return 0;
}
